PREFIX pq: <http://www.wikidata.org/prop/qualifier/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX ps: <http://www.wikidata.org/prop/statement/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?country ?countryLabel ?area ?countryPopulation ?capital ?capitalLabel ?capitalPopulation WHERE {
  ?country p:P463 ?membership .
  ?membership ps:P463 wd:Q458 .
  ?country wdt:P31 wd:Q6256 .
  ?country rdfs:label ?countryLabel .
  FILTER(LANG(?countryLabel) = 'en')
  OPTIONAL {
    ?country wdt:P2046 ?area
  }
  OPTIONAL {
    ?country wdt:P1082 ?countryPopulation
  }
  OPTIONAL {
    ?country wdt:P36 ?capital .
    ?capital rdfs:label ?capitalLabel .
    FILTER(LANG(?capitalLabel) = 'en')
    OPTIONAL {
      ?capital wdt:P1082 ?capitalPopulation
    }
  }
  FILTER NOT EXISTS {
    ?membership pq:P582 ?endTime
  }
}
ORDER BY ?countryLabel
